import { backendURL } from "../Globals";

let SearchComponent = () => {

    let [issn, setIssn] = useState("");

    let ChangeIssn = (e) => {
        set("ChangeIssn"+e.currentTarget.value)
    }

    let clickSearch = async () => {
        let response = await fetch(backendURL+"search")
    }


    return (
        <div className="search-form">
            <h2>Encuentra una revista participante</h2>
            <input type="text" className="search-input" placeholder="issn" onChange={ChangeIssn}/>
            <button className="search-button" onClick={clickSearch}>Search</button>
        </div>
    )
}

export default SearchComponent;
